mapper.select:
SELECT mnum, name, nick, email, mphone, storecode, storeaddr, authority, regdate row_num FROM (SELECT mnum, name, nick, email, mphone, storecode, storeaddr, authority, regdate, ROW_NUMBER() OVER(ORDER BY cnum desc) AS row_num FROM member
cwriter like '%' || #{searchValue} || '%'
ctitle like '%' || #{searchValue} || '%'
ccontent like '%' || #{searchValue} || '%'
) numbered_rows WHERE row_num BETWEEN #{begin} AND #{end}
